"use client";

import React from 'react';
import { motion } from 'framer-motion';
import { Button } from '../global/Button';
import Link from 'next/link';
import dynamic from 'next/dynamic';

const Hero3D = dynamic(() => import('./Hero3D').then((mod) => mod.Hero3D), {
  ssr: false,
});

export const HeroSection = () => {
  return (
    <section className="relative min-h-screen flex items-center justify-center overflow-hidden bg-slate-950 pt-20">
      {/* 3D Background */}
      <Hero3D />

      {/* Radial Gradient overlay for depth */}
      <div className="absolute inset-0 bg-gradient-to-b from-transparent via-slate-950/50 to-slate-950 z-10" />

      <div className="relative z-20 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center flex flex-col items-center">
        
        {/* Animated Badge */}
        <motion.div
          initial={{ opacity: 0, scale: 0.8, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.2, ease: [0.16, 1, 0.3, 1] }}
          className="mb-8 relative"
        >
          <div className="absolute inset-0 bg-accent/20 blur-xl rounded-full" />
          <span className="relative inline-block px-6 py-2 text-sm font-bold tracking-widest text-accent uppercase bg-white/5 border border-accent/20 rounded-full backdrop-blur-md">
            Unlock Your Potential
          </span>
        </motion.div>
        
        {/* Kinetic Typography Heading */}
        <h1 className="text-5xl md:text-7xl lg:text-8xl font-extrabold text-white tracking-tighter mb-8 leading-[1.1]">
          <motion.div 
            initial={{ opacity: 0, y: 40 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 1, delay: 0.3, ease: [0.16, 1, 0.3, 1] }}
            className="overflow-hidden"
          >
            Shape Your Future
          </motion.div>
          <motion.div 
            initial={{ opacity: 0, y: 40 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 1, delay: 0.4, ease: [0.16, 1, 0.3, 1] }}
            className="overflow-hidden mt-2"
          >
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 via-primary to-accent">
              YP Gurukul
            </span>
          </motion.div>
        </h1>
        
        {/* Description */}
        <motion.p 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 1.2, delay: 0.8 }}
          className="mt-6 text-lg md:text-xl text-slate-400 max-w-2xl mx-auto mb-12 font-medium"
        >
          Premium classroom coaching and foundation courses designed to build strong fundamentals and ensure competitive success in a 3D world.
        </motion.p>
        
        {/* Actions */}
        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 1, ease: [0.16, 1, 0.3, 1] }}
          className="flex flex-col sm:flex-row justify-center gap-6 w-full"
        >
          <Link href="/courses">
            <Button size="lg" className="w-full sm:w-auto h-14 px-8 rounded-full bg-primary hover:bg-primary-dark shadow-[0_0_40px_rgba(59,130,246,0.3)] hover:shadow-[0_0_60px_rgba(59,130,246,0.5)] transition-all text-base tracking-wide font-bold">
              Explore Courses
            </Button>
          </Link>
          <Link href="/contact">
            <Button variant="outline" size="lg" className="w-full sm:w-auto h-14 px-8 rounded-full text-white border-white/20 hover:bg-white/10 backdrop-blur-md transition-all text-base tracking-wide font-bold">
              Book a Campus Visit
            </Button>
          </Link>
        </motion.div>
      </div>
    </section>
  );
};
